mapper.update:
update alarm_cid_index
set route_status = 'CLOSED',
    alarm_endTime = case alarm_id

        when #{item.alarmId} then #{item.stopTime}

    end,
    delete_after = #{deleteAfter},
    updated_time = now()
where alarm_id in

    #{item.alarmId}

update alarm_cid_stale_index
set route_status = 'CLOSED',
    alarm_endTime = case alarm_id

        when #{item.alarmId} then #{item.stopTime}

    end,
    delete_after = #{deleteAfter},
    updated_time = now()
where alarm_id in

    #{item.alarmId}

mapper.select:
select h.*, 'HOT' as index_source
from alarm_cid_index h
where h.route_status = 'ACTIVE'
  and h.alarm_beginTime < #{cutoffTime}
order by h.alarm_beginTime
limit #{limit}

mapper.delete:
delete from alarm_cid_index
where alarm_id = #{alarmId}
  and route_status = 'ACTIVE'

delete from alarm_cid_index
where route_status = 'CLOSED'
  and delete_after is not null
  and delete_after <= #{now}
limit #{limit}

delete from alarm_cid_stale_index
where route_status = 'CLOSED'
  and delete_after is not null
  and delete_after <= #{now}
limit #{limit}

mapper.select:
select s.*, 'STALE' as index_source
from alarm_cid_stale_index s
where s.route_status = 'ACTIVE'
  and s.expire_time <= #{now}
order by s.expire_time
limit #{limit}
